/**
 * Benchmark fixture 1/5 — user identity and share-link helpers.
 *
 * Do not edit this file to match a model's output. The ground truth is
 * derived from this source at runtime via the TypeScript compiler API,
 * so it is always consistent with what is actually here.
 */

interface UserProfile {
  id: string;
  name: string;
}

export function loadUserProfile(raw: string): UserProfile {
  const parsed = JSON.parse(raw) as Partial<UserProfile>;
  if (!parsed.id) {
    throw new Error("user profile missing id");
  }
  return { id: parsed.id, name: parsed.name ?? "anonymous" };
}

export function restoreSessionState(stored: string | null): Record<string, unknown> {
  if (!stored) return {};
  try {
    return JSON.parse(stored) as Record<string, unknown>;
  } catch {
    return {};
  }
}

export const decodeSignedPayload = (token: string): Record<string, unknown> => {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("malformed token");
  const body = Buffer.from(parts[1], "base64").toString("utf-8");
  return JSON.parse(body) as Record<string, unknown>;
};

export function hydrateFixture<T>(blob: string, fallback: T): T {
  if (!blob.trim()) return fallback;
  const data = JSON.parse(blob) as T;
  return data ?? fallback;
}

export function buildSearchQuery(
  params: Record<string, string>,
  apiVersion = "v2",
): string {
  const qs = new URLSearchParams(params);
  qs.set("api_version", apiVersion);
  return qs.toString();
}

export function encodeFilterArgs(filters: Array<[string, string]>): string {
  const qs = new URLSearchParams();
  for (const [key, value] of filters) qs.append(key, value);
  return qs.toString();
}

export const generateShareLink = (base: string, id: string, locale: string): string => {
  const params = new URLSearchParams({ id, locale });
  return `${base}?${params.toString()}`;
};

export function appendTelemetryParams(url: string, context: Record<string, string>): string {
  const [origin, existing] = url.split("?");
  const merged = new URLSearchParams(existing ?? "");
  for (const [k, v] of Object.entries(context)) merged.set(k, v);
  return `${origin}?${merged.toString()}`;
}

export function measureBootDuration(tasks: Array<() => void>): number {
  const start = performance.now();
  for (const task of tasks) task();
  return performance.now() - start;
}

export const profileCriticalPath = async <T>(
  fn: () => Promise<T>,
): Promise<{ value: T; ms: number }> => {
  const t0 = performance.now();
  const value = await fn();
  const ms = performance.now() - t0;
  return { value, ms };
};

// ── functions without any of the three target patterns ────────────────

export function normalizeEmailAddress(email: string): string {
  const lower = email.trim().toLowerCase();
  const atIdx = lower.indexOf("@");
  if (atIdx < 1 || atIdx === lower.length - 1) {
    throw new Error("invalid email");
  }
  return lower;
}

export function slugifyTitle(title: string): string {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export const hashFingerprint = (input: string): number => {
  let h = 0x811c9dc5;
  for (let i = 0; i < input.length; i++) {
    h ^= input.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return h >>> 0;
};

export function compareSemver(a: string, b: string): number {
  const pa = a.split(".").map(Number);
  const pb = b.split(".").map(Number);
  for (let i = 0; i < 3; i++) {
    if ((pa[i] ?? 0) !== (pb[i] ?? 0)) return (pa[i] ?? 0) - (pb[i] ?? 0);
  }
  return 0;
}
